// // This module implements a 4-bit binary counter with asynchronous reset. The counter decrements its value on every positive edge of the clock. If the reset signal (rst) is low, the counter resets to 4'b1111 on the next clock edge.
module counter_4bit (clk, rst, q);
   input clk, rst;
   output [3:0] q;

   reg [3:0] q;

always @(posedge clk) begin
    if (rst) begin
        q <= 4'b0000;
    end else begin
        q <= q + 1;
    end
end

endmodule
